create or replace function private.get_business_assets_snapshot_internal(p_business_id uuid,p_limit integer default 150) returns jsonb language plpgsql stable security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();can_manage boolean;can_depreciate boolean;can_dispose boolean;normalized_limit integer:=greatest(1,least(coalesce(p_limit,150),300)); begin if actor_id is null or not private.can_view_business_assets(p_business_id) then raise exception 'Fixed asset view permission required.' using errcode='42501';end if; can_manage:=private.can_manage_business_assets(p_business_id); can_depreciate:=private.can_depreciate_business_assets(p_business_id); can_dispose:=private.can_dispose_business_assets(p_business_id); return jsonb_build_object('summary',jsonb_build_object('draft_assets',(select count(*) from public.business_fixed_assets asset where asset.business_id=p_business_id and asset.status='draft' and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id))),'active_assets',(select count(*) from public.business_fixed_assets asset where asset.business_id=p_business_id and asset.status in ('active','fully_depreciated') and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id))),'original_cost',(select coalesce(sum(asset.original_cost),0) from public.business_fixed_assets asset where asset.business_id=p_business_id and asset.status in ('active','fully_depreciated') and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id))),'accumulated_depreciation',(select coalesce(sum(asset.accumulated_depreciation),0) from public.business_fixed_assets asset where asset.business_id=p_business_id and asset.status in ('active','fully_depreciated') and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id))),'net_book_value',(select coalesce(sum(asset.book_value),0) from public.business_fixed_assets asset where asset.business_id=p_business_id and asset.status in ('active','fully_depreciated') and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id))),'draft_runs',(select count(*) from public.business_asset_depreciation_runs run where run.business_id=p_business_id and run.status='draft' and (run.branch_id is null or private.has_business_branch_access(p_business_id,run.branch_id,actor_id)))),'settings',(select to_jsonb(settings) from public.business_asset_settings settings where settings.business_id=p_business_id),'categories',coalesce((select jsonb_agg(to_jsonb(row_data) order by row_data.active desc,row_data.code) from (select category.*,asset_account.code asset_account_code,asset_account.name asset_account_name,accumulated_account.code accumulated_account_code,accumulated_account.name accumulated_account_name,expense_account.code expense_account_code,expense_account.name expense_account_name from public.business_asset_categories category join public.business_chart_of_accounts asset_account on asset_account.id=category.asset_account_id join public.business_chart_of_accounts accumulated_account on accumulated_account.id=category.accumulated_depreciation_account_id join public.business_chart_of_accounts expense_account on expense_account.id=category.depreciation_expense_account_id where category.business_id=p_business_id) row_data),'[]'::jsonb),'assets',coalesce((select jsonb_agg(to_jsonb(row_data) order by row_data.created_at desc) from (select asset.*,'AST-'||lpad(asset.asset_no::text,8,'0') asset_display_code,category.code category_code,category.name category_name,branch.name branch_name,capitalization_journal.journal_number capitalization_journal_number,disposal_journal.journal_number disposal_journal_number from public.business_fixed_assets asset join public.business_asset_categories category on category.id=asset.category_id left join public.business_branches branch on branch.id=asset.branch_id left join public.business_journal_entries capitalization_journal on capitalization_journal.id=asset.capitalization_journal_entry_id left join public.business_journal_entries disposal_journal on disposal_journal.id=asset.disposal_journal_entry_id where asset.business_id=p_business_id and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id)) order by asset.created_at desc limit normalized_limit) row_data),'[]'::jsonb),'runs',coalesce((select jsonb_agg(to_jsonb(row_data) order by row_data.period_start desc,row_data.run_no desc) from (select run.*,'DEP-'||lpad(run.run_no::text,8,'0') run_code,branch.name branch_name,journal.journal_number from public.business_asset_depreciation_runs run left join public.business_branches branch on branch.id=run.branch_id left join public.business_journal_entries journal on journal.id=run.journal_entry_id where run.business_id=p_business_id and (run.branch_id is null or private.has_business_branch_access(p_business_id,run.branch_id,actor_id)) order by run.period_start desc,run.run_no desc limit normalized_limit) row_data),'[]'::jsonb),'lines',coalesce((select jsonb_agg(to_jsonb(row_data) order by row_data.depreciation_run_id,row_data.asset_code) from (select line.*,asset.asset_code,asset.name asset_name from public.business_asset_depreciation_lines line join public.business_fixed_assets asset on asset.business_id=line.business_id and asset.id=line.asset_id join public.business_asset_depreciation_runs run on run.business_id=line.business_id and run.id=line.depreciation_run_id where line.business_id=p_business_id and (run.branch_id is null or private.has_business_branch_access(p_business_id,run.branch_id,actor_id))) row_data),'[]'::jsonb),'branches',coalesce((select jsonb_agg(jsonb_build_object('id',branch.id,'code',branch.code,'name',branch.name,'is_primary',branch.is_primary) order by branch.is_primary desc,branch.name) from public.business_branches branch where branch.business_id=p_business_id and branch.status='active' and private.has_business_branch_access(p_business_id,branch.id,actor_id)),'[]'::jsonb),'asset_accounts',case when can_manage then coalesce((select jsonb_agg(jsonb_build_object('id',account.id,'code',account.code,'name',account.name,'account_type',account.account_type,'account_subtype',account.account_subtype,'normal_balance',account.normal_balance,'system_key',account.system_key) order by account.code) from public.business_chart_of_accounts account where account.business_id=p_business_id and account.is_active and ((account.account_type='asset') or account.account_type='expense')),'[]'::jsonb) else '[]'::jsonb end,'counter_accounts',case when can_manage then coalesce((select jsonb_agg(jsonb_build_object('id',account.id,'code',account.code,'name',account.name,'account_type',account.account_type,'normal_balance',account.normal_balance,'system_key',account.system_key) order by account.code) from public.business_chart_of_accounts account where account.business_id=p_business_id and account.is_active),'[]'::jsonb) else '[]'::jsonb end,'disposal_accounts',case when can_dispose then coalesce((select jsonb_agg(jsonb_build_object('id',account.id,'code',account.code,'name',account.name,'system_key',account.system_key) order by account.code) from public.business_chart_of_accounts account where account.business_id=p_business_id and account.is_active and account.account_type='asset' and account.normal_balance='debit' and coalesce(account.account_subtype,'')<>'contra_asset'),'[]'::jsonb) else '[]'::jsonb end,'audit',coalesce((select jsonb_agg(to_jsonb(row_data) order by row_data.created_at desc) from (select audit.*,coalesce(nullif(btrim(profile.full_name),''),nullif(split_part(profile.email,'@',1),''),'System') actor_name from public.business_asset_audit_log audit left join public.profiles profile on profile.id=audit.actor_user_id where audit.business_id=p_business_id order by audit.created_at desc limit normalized_limit) row_data),'[]'::jsonb),'capabilities',jsonb_build_object('can_manage',can_manage,'can_depreciate',can_depreciate,'can_dispose',can_dispose)); end;$$;

create or replace function public.upsert_business_asset_category(p_business_id uuid,p_category_id uuid,p_code text,p_name text,p_description text,p_asset_account_id uuid,p_accumulated_depreciation_account_id uuid,p_depreciation_expense_account_id uuid,p_default_useful_life_months integer,p_default_residual_rate numeric,p_default_depreciation_convention text,p_active boolean default true) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.upsert_business_asset_category_internal(p_business_id,p_category_id,p_code,p_name,p_description,p_asset_account_id,p_accumulated_depreciation_account_id,p_depreciation_expense_account_id,p_default_useful_life_months,p_default_residual_rate,p_default_depreciation_convention,p_active);$$;

create or replace function public.upsert_business_fixed_asset(p_business_id uuid,p_asset_id uuid,p_category_id uuid,p_branch_id uuid,p_asset_code text,p_name text,p_description text,p_serial_number text,p_location text,p_acquisition_date date,p_in_service_date date,p_original_cost numeric,p_residual_value numeric,p_useful_life_months integer,p_depreciation_convention text) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.upsert_business_fixed_asset_internal(p_business_id,p_asset_id,p_category_id,p_branch_id,p_asset_code,p_name,p_description,p_serial_number,p_location,p_acquisition_date,p_in_service_date,p_original_cost,p_residual_value,p_useful_life_months,p_depreciation_convention);$$;

create or replace function public.activate_business_fixed_asset(p_business_id uuid,p_asset_id uuid,p_counter_account_id uuid,p_posting_date date,p_reference text default null) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.activate_business_fixed_asset_internal(p_business_id,p_asset_id,p_counter_account_id,p_posting_date,p_reference);$$;

create or replace function public.create_business_asset_depreciation_run(p_business_id uuid,p_period_start date,p_posting_date date,p_branch_id uuid default null,p_notes text default null) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.create_business_asset_depreciation_run_internal(p_business_id,p_period_start,p_posting_date,p_branch_id,p_notes);$$;

create or replace function public.recalculate_business_asset_depreciation_run(p_business_id uuid,p_run_id uuid) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.recalculate_business_asset_depreciation_run_internal(p_business_id,p_run_id);$$;

create or replace function public.post_business_asset_depreciation_run(p_business_id uuid,p_run_id uuid) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.post_business_asset_depreciation_run_internal(p_business_id,p_run_id);$$;

create or replace function public.cancel_business_asset_depreciation_run(p_business_id uuid,p_run_id uuid,p_reason text default null) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.cancel_business_asset_depreciation_run_internal(p_business_id,p_run_id,p_reason);$$;

create or replace function public.dispose_business_fixed_asset(p_business_id uuid,p_asset_id uuid,p_disposal_date date,p_proceeds numeric,p_disposal_account_id uuid,p_reference text default null,p_write_off boolean default false) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.dispose_business_fixed_asset_internal(p_business_id,p_asset_id,p_disposal_date,p_proceeds,p_disposal_account_id,p_reference,p_write_off);$$;

create or replace function public.cancel_draft_business_fixed_asset(p_business_id uuid,p_asset_id uuid,p_reason text default null) returns jsonb language sql set search_path=pg_catalog,public,private as $$select private.cancel_draft_business_fixed_asset_internal(p_business_id,p_asset_id,p_reason);$$;

create or replace function public.get_business_assets_snapshot(p_business_id uuid,p_limit integer default 150) returns jsonb language sql stable set search_path=pg_catalog,public,private as $$select private.get_business_assets_snapshot_internal(p_business_id,p_limit);$$;

revoke execute on function public.upsert_business_asset_category(uuid,uuid,text,text,text,uuid,uuid,uuid,integer,numeric,text,boolean),public.upsert_business_fixed_asset(uuid,uuid,uuid,uuid,text,text,text,text,text,date,date,numeric,numeric,integer,text),public.activate_business_fixed_asset(uuid,uuid,uuid,date,text),public.create_business_asset_depreciation_run(uuid,date,date,uuid,text),public.recalculate_business_asset_depreciation_run(uuid,uuid),public.post_business_asset_depreciation_run(uuid,uuid),public.cancel_business_asset_depreciation_run(uuid,uuid,text),public.dispose_business_fixed_asset(uuid,uuid,date,numeric,uuid,text,boolean),public.cancel_draft_business_fixed_asset(uuid,uuid,text),public.get_business_assets_snapshot(uuid,integer) from public,anon;

grant execute on function public.upsert_business_asset_category(uuid,uuid,text,text,text,uuid,uuid,uuid,integer,numeric,text,boolean),public.upsert_business_fixed_asset(uuid,uuid,uuid,uuid,text,text,text,text,text,date,date,numeric,numeric,integer,text),public.activate_business_fixed_asset(uuid,uuid,uuid,date,text),public.create_business_asset_depreciation_run(uuid,date,date,uuid,text),public.recalculate_business_asset_depreciation_run(uuid,uuid),public.post_business_asset_depreciation_run(uuid,uuid),public.cancel_business_asset_depreciation_run(uuid,uuid,text),public.dispose_business_fixed_asset(uuid,uuid,date,numeric,uuid,text,boolean),public.cancel_draft_business_fixed_asset(uuid,uuid,text),public.get_business_assets_snapshot(uuid,integer) to authenticated;

alter table public.business_asset_settings enable row level security;

alter table public.business_asset_categories enable row level security;

alter table public.business_fixed_assets enable row level security;

alter table public.business_asset_depreciation_runs enable row level security;

alter table public.business_asset_depreciation_lines enable row level security;

alter table public.business_asset_audit_log enable row level security;

drop policy if exists business_asset_settings_select on public.business_asset_settings;
create policy business_asset_settings_select on public.business_asset_settings for select to authenticated using(private.can_view_business_assets(business_id));

drop policy if exists business_asset_categories_select on public.business_asset_categories;
create policy business_asset_categories_select on public.business_asset_categories for select to authenticated using(private.can_view_business_assets(business_id));

drop policy if exists business_fixed_assets_select on public.business_fixed_assets;
create policy business_fixed_assets_select on public.business_fixed_assets for select to authenticated using(private.can_view_business_assets(business_id) and (branch_id is null or private.has_business_branch_access(business_id,branch_id,(select auth.uid()))));

drop policy if exists business_asset_depreciation_runs_select on public.business_asset_depreciation_runs;
create policy business_asset_depreciation_runs_select on public.business_asset_depreciation_runs for select to authenticated using(private.can_view_business_assets(business_id) and (branch_id is null or private.has_business_branch_access(business_id,branch_id,(select auth.uid()))));

drop policy if exists business_asset_depreciation_lines_select on public.business_asset_depreciation_lines;
create policy business_asset_depreciation_lines_select on public.business_asset_depreciation_lines for select to authenticated using(private.can_view_business_assets(business_id) and exists(select 1 from public.business_asset_depreciation_runs run where run.business_id=business_asset_depreciation_lines.business_id and run.id=business_asset_depreciation_lines.depreciation_run_id and (run.branch_id is null or private.has_business_branch_access(run.business_id,run.branch_id,(select auth.uid())))));

drop policy if exists business_asset_audit_select on public.business_asset_audit_log;
create policy business_asset_audit_select on public.business_asset_audit_log for select to authenticated using(private.can_view_business_assets(business_id));

revoke all on public.business_asset_settings,public.business_asset_categories,public.business_fixed_assets,public.business_asset_depreciation_runs,public.business_asset_depreciation_lines,public.business_asset_audit_log from anon,authenticated;

grant select on public.business_asset_settings,public.business_asset_categories,public.business_fixed_assets,public.business_asset_depreciation_runs,public.business_asset_depreciation_lines,public.business_asset_audit_log to authenticated;

revoke execute on function private.can_view_business_assets(uuid),private.can_manage_business_assets(uuid),private.can_depreciate_business_assets(uuid),private.can_dispose_business_assets(uuid) from public,anon;

grant execute on function private.can_view_business_assets(uuid),private.can_manage_business_assets(uuid),private.can_depreciate_business_assets(uuid),private.can_dispose_business_assets(uuid) to authenticated;
